(function () {
  const React = window.React;
  const ReactDOM = window.ReactDOM;

  class ColorPickerModal extends React.Component {
    constructor(props) {
      super(props);
      this.state = {
        color: props.entity ? props.entity.getData().color : '#ff0000',
      };
    }

    handleChange = (e) => {
      this.setState({ color: e.target.value });
    };

    applyColor = () => {
      this.props.onComplete({
        color: this.state.color,
        style: `color: ${this.state.color}`,
      });
    };

    render() {
      return (
        <div className="color-picker-modal">
          <label>Select a color:</label>
          <input
            type="color"
            value={this.state.color}
            onChange={this.handleChange}
          />
          <button type="button" onClick={this.applyColor}>
            Apply
          </button>
        </div>
      );
    }
  }

  window.draftail.registerPlugin({
    type: 'COLOR',
    source: (props) => {
      const container = document.createElement("div");
      setTimeout(() => {
        ReactDOM.render(<ColorPickerModal {...props} />, container);
      }, 0);
      return container;
    },
    decorator: ({ children, entity }) => {
      const { color } = entity.getData();
      return <span style={{ color }}>{children}</span>;
    },
  });
})();

